    private fun w(es: String, ru: String, ex: String = "", level: String = "B1", cat: String = "general", type: String = "noun") =
        WordEntity(spanish = es, russian = ru, example = ex, level = level, category = cat, wordType = type)
    private fun v(es: String, ru: String, ex: String = "", level: String = "B1", cat: String = "general") = w(es, ru, ex, level, cat, "verb")
    private fun adj(es: String, ru: String, ex: String = "", level: String = "B1", cat: String = "general") = w(es, ru, ex, level, cat, "adjective")
    private fun adv(es: String, ru: String, ex: String = "", level: String = "B1", cat: String = "general") = w(es, ru, ex, level, cat, "adverb")
    private fun ph(es: String, ru: String, ex: String = "", level: String = "B1") = w(es, ru, ex, level, "expresiones", "phrase")

    val entries: List<WordEntity> get() = salud + politica + ecologia + economia +
        cultura + ciencia + psicologia + derecho + cocina + deportes +
